/* Example using Google Fonts Inter (variable font) */
.heading-primary {
  font-family: "Inter", sans-serif; /* Or 'Inter var' for older implementations */
  font-size: 3rem;
  font-weight: 400; /* Base weight */
  /* Adjust weight and slant axes */
  font-variation-settings: "wght" 700, "slnt" -10; 
  line-height: 1.2;
}

@media (max-width: 768px) {
  .heading-primary {
    /* Dynamically adjust for smaller screens */
    font-variation-settings: "wght" 500, "wdth" 90; /* Shorter width, lighter weight */
    font-size: 2rem;
  }
}

/* Example with a more experimental variable font (e.g., Decovar) */
.call-to-action {
  font-family: "Decovar Alpha", sans-serif;
  font-size: 1.8rem;
  /* Control custom design axes like 'GRAD' (grade) and 'SOFT' (softness) */
  font-variation-settings: "GRAD" 100, "SOFT" 50;
  text-transform: uppercase;
}
